+    #[test]
+    fn test_lerp_color() {
+        let black = PackedRgba::rgb(0, 0, 0);
+        let white = PackedRgba::rgb(255, 255, 255);
+
+        let mid = lerp_color(black, white, 0.5);
+        assert_eq!(mid.r(), 127);
+        assert_eq!(mid.g(), 127);
+        assert_eq!(mid.b(), 127);
+
+        let zero = lerp_color(black, white, 0.0);
+        assert_eq!(zero.r(), 0);
+
+        let one = lerp_color(black, white, 1.0);
+        assert_eq!(one.r(), 255);
+    }
