+    #[test]
+    fn test_apply_alpha() {
+        let color = PackedRgba::rgb(200, 100, 50);
+
+        let half = apply_alpha(color, 0.5);
+        assert_eq!(half.r(), 100);
+        assert_eq!(half.g(), 50);
+        assert_eq!(half.b(), 25);
+
+        let zero = apply_alpha(color, 0.0);
+        assert_eq!(zero.r(), 0);
+    }
+
