+// =============================================================================
+// TransitionState - Animation state manager
+// =============================================================================
+
+/// Helper for managing transition animations.
+#[derive(Debug, Clone)]
+pub struct TransitionState {
+    progress: f64,
+    active: bool,
+    speed: f64,
+    title: String,
+    subtitle: String,
+    color: PackedRgba,
+    gradient: Option<ColorGradient>,
+    time: f64,
+}
+
+impl Default for TransitionState {
+    fn default() -> Self {
+        Self::new()
+    }
+}
+
+impl TransitionState {
+    /// Create new transition state.
+    pub fn new() -> Self {
+        Self {
+            progress: 0.0,
+            active: false,
+            speed: 0.05,
+            title: String::new(),
+            subtitle: String::new(),
+            color: PackedRgba::rgb(255, 100, 200),
+            gradient: None,
+            time: 0.0,
+        }
+    }
+
+    /// Start a transition.
+    pub fn start(
+        &mut self,
+        title: impl Into<String>,
+        subtitle: impl Into<String>,
+        color: PackedRgba,
+    ) {
+        self.title = title.into();
+        self.subtitle = subtitle.into();
+        self.color = color;
+        self.gradient = None;
+        self.progress = 0.0;
+        self.active = true;
+    }
+
+    /// Start a transition with gradient.
+    pub fn start_with_gradient(
+        &mut self,
+        title: impl Into<String>,
+        subtitle: impl Into<String>,
+        gradient: ColorGradient,
+    ) {
+        self.title = title.into();
+        self.subtitle = subtitle.into();
+        self.gradient = Some(gradient);
+        self.progress = 0.0;
+        self.active = true;
+    }
+
+    /// Set transition speed.
+    pub fn set_speed(&mut self, speed: f64) {
+        self.speed = speed.clamp(0.01, 0.5);
+    }
+
+    /// Update the transition (call every tick).
+    pub fn tick(&mut self) {
+        self.time += 0.1;
+        if self.active {
+            self.progress += self.speed;
+            if self.progress >= 1.0 {
+                self.progress = 1.0;
+                self.active = false;
+            }
+        }
+    }
+
+    /// Check if visible.
+    pub fn is_visible(&self) -> bool {
+        self.active || (self.progress > 0.0 && self.progress < 1.0)
+    }
+
+    /// Check if active.
+    pub fn is_active(&self) -> bool {
+        self.active
+    }
+
+    /// Get current progress.
+    pub fn progress(&self) -> f64 {
+        self.progress
+    }
+
+    /// Get the overlay widget.
+    pub fn overlay(&self) -> TransitionOverlay {
+        let mut overlay = TransitionOverlay::new(&self.title, &self.subtitle)
+            .progress(self.progress)
+            .primary_color(self.color)
+            .time(self.time);
+
+        if let Some(ref gradient) = self.gradient {
+            overlay = overlay.gradient(gradient.clone());
+        }
+
+        overlay
+    }
+}
